def seed_ap_hc_questions_inner(conn, db_exec, ph):
    """
    Insert all AP_HC questions into the `questions` table.
    Skips any question already present (same folder+topic+question_text).
    Returns count of newly inserted rows.
    """
    inserted = 0
    for row in AP_HC_QUESTIONS:
        folder, topic, q_text, opt_a, opt_b, opt_c, opt_d, ans, diff = row
        # Check for duplicate
        cur = db_exec(conn,
            f"SELECT id FROM questions WHERE folder={ph} AND topic={ph} AND question_text={ph}",
            (folder, topic, q_text))
        if cur.fetchone():
            continue
        db_exec(conn,
            f"""INSERT INTO questions
                (folder, topic, source_file, question_text,
                 option_a, option_b, option_c, option_d,
                 correct_answer, difficulty)
                VALUES ({ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph})""",
            (folder, topic, 'ap_hc_seed', q_text,
             opt_a, opt_b, opt_c, opt_d, ans, diff))
        inserted += 1
    conn.commit()
    return inserted
